section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/cross-platform-token-distribution.json",
  "title": "Cross-Platform Token Distribution",
  "type": "object",
  "required": [
    "artefact_id",
    "pipeline_id",
    "source",
    "transforms",
    "platform_outputs",
    "ci_check_ref",
    "drift_policy",
    "owners",
    "last_synced_at",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "pipeline_id": {
      "type": "string",
      "description": "pipeline_id",
      "minLength": 1
    },
    "source": {
      "type": "string",
      "description": "source",
      "minLength": 1
    },
    "transforms": {
      "type": "array",
      "description": "transforms (array)",
      "minItems": 1
    },
    "platform_outputs": {
      "type": "array",
      "description": "platform_outputs (array)",
      "minItems": 1
    },
    "ci_check_ref": {
      "type": "string",
      "description": "ci_check_ref",
      "minLength": 1
    },
    "drift_policy": {
      "type": "string",
      "description": "drift_policy",
      "minLength": 1
    },
    "owners": {
      "type": "string",
      "description": "owners",
      "minLength": 1
    },
    "last_synced_at": {
      "type": "string",
      "description": "last_synced_at (ISO-8601)",
      "format": "date-time"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
